export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  return inputs.subscriptions && inputs.subscriptions.length > 5;
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;

  return {
    average,
  };
};

export const code = async (inputs) => {
  const grouped = {};

  for (const [cost, date, resourceId, currency] of inputs.costs) {
    if (!grouped[resourceId]) {
      grouped[resourceId] = {
        resourceId,
        currency,
        datesWithCosts: []
      };
    }

    grouped[resourceId].datesWithCosts.push([cost, date]);
  }

  return Object.values(grouped);
};

export const code = async (inputs) => {
  const items = inputs.pricingItems || [];

  const today = new Date();
  const dateKey = Number(
    `${today.getUTCFullYear()}${String(today.getUTCMonth() + 1).padStart(2, "0")}${String(today.getUTCDate()).padStart(2, "0")}`
  );

  return items
    .map(item => {
      const parsedItem = typeof item === "string" ? JSON.parse(item) : item;

      return {
        resourceId: parsedItem.resourceId,
        currency: parsedItem.currency || "USD",
        datesWithCosts: [
          [
            parsedItem.dailyPricing || 0,
            dateKey
          ]
        ]
      };
    })
    .filter(item => item.resourceId);
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.avgCpuMetrics?.timeseries ?? inputs?.avgCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

   return seriesArr.reduce((globalMax, { data }) => {
    if (!Array.isArray(data)) return globalMax;

    const localMax = data.reduce((m, { average }) =>
      typeof average === 'number' && average > m ? average : m
    , 0);

    return localMax > globalMax ? localMax : globalMax;
  }, 0);
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.maxCpuMetrics?.timeseries ?? inputs?.maxCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

  return seriesArr.reduce((max, series) => {
    if (!Array.isArray(series?.data)) return max;

    const seriesMax = series.data.reduce((m, p) => {
      return typeof p?.maximum === "number" && p.maximum > m ? p.maximum : m;
    }, 0);

    return seriesMax > max ? seriesMax : max;
  }, 0);
};

export const code = async (inputs) => {
  const toSeriesArr = (metric) => {
    if (!metric) return [];
    if (Array.isArray(metric) && metric.length) {
      if (metric[0]?.data) return metric;
      return metric.flatMap(toSeriesArr);
    }
    if (Array.isArray(metric.timeseries)) return metric.timeseries;
    if (Array.isArray(metric.value)) return metric.value.flatMap(toSeriesArr);
    return [];
  };

  const inSeries  = toSeriesArr(inputs?.networkInMetrics);
  const outSeries = toSeriesArr(inputs?.networkOutMetrics);

  const buckets = new Map();

  const addSeries = (seriesArr) => {
    seriesArr.forEach(({ data = [] }) =>
      data.forEach(({ timeStamp, average }) => {
        if (typeof average !== 'number' || !timeStamp) return;
        buckets.set(timeStamp, (buckets.get(timeStamp) || 0) + average);
      })
    );
  };

  addSeries(inSeries);
  addSeries(outSeries);

  let maxBps = 0;
  for (const v of buckets.values()) if (v > maxBps) maxBps = v;

  return (maxBps * 3600) / (1024 * 1024); // MB/h
};

export const code = async (inputs) => {
  const { vm, priceList } = inputs;

  const items = Array.isArray(priceList)
    ? priceList
    : Array.isArray(priceList?.Items)
      ? priceList.Items
      : [];

  const resourceId = vm?.id || vm?.resourceMetadata?.resourceId || null;

  const vmSize = vm?.hardwareProfile?.vmSize || null;

  const osType =
    vm?.storageProfile?.osDisk?.osType ||
    (vm?.osProfile?.windowsConfiguration ? "Windows" : null) ||
    (vm?.osProfile?.linuxConfiguration ? "Linux" : null);

  const isWindows = String(osType || "").toLowerCase() === "windows";

  const isSpot =
    String(vm?.priority || "").toLowerCase() === "spot" ||
    vm?.evictionPolicy != null ||
    vm?.billingProfile?.maxPrice != null;

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/[_-]/g, "")
      .replace(/\s+/g, "")
      .replace("standard", "")
      .trim();

  const expectedSku = normalize(vmSize);

  if (!vmSize) {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const priceItem = items.find((p) => {
    if (p.type !== "Consumption" && p.priceType !== "Consumption") return false;
    if (p.serviceName !== "Virtual Machines") return false;
    if (p.unitOfMeasure !== "1 Hour") return false;

    const armSkuName = normalize(p.armSkuName);
    const skuName = normalize(p.skuName);
    const meterName = normalize(p.meterName);

    const rawSkuName = String(p.skuName || "").toLowerCase();
    const rawMeterName = String(p.meterName || "").toLowerCase();
    const productName = String(p.productName || "").toLowerCase();

    const isPriceSpot =
      rawSkuName.includes("spot") ||
      rawMeterName.includes("spot");

    const isPriceLowPriority =
      rawSkuName.includes("low priority") ||
      rawMeterName.includes("low priority");

    const isPriceWindows = productName.includes("windows");

    if (
      armSkuName !== expectedSku &&
      skuName !== expectedSku &&
      meterName !== expectedSku
    ) {
      return false;
    }

    if (isPriceSpot !== isSpot) {
      return false;
    }

    if (isPriceLowPriority) {
      return false;
    }

    if (isPriceWindows !== isWindows) {
      return false;
    }

    return true;
  });

  if (!priceItem) {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const hourlyPrice =
    typeof priceItem.unitPrice === "number"
      ? priceItem.unitPrice
      : typeof priceItem.retailPrice === "number"
        ? priceItem.retailPrice
        : 0;

  return {
    resourceId,
    dailyPricing: hourlyPrice * 24,
    currency: priceItem.currencyCode || "USD"
  };
};
